<?php
namespace Tests\Feature;
use App\Domain\Hunts\Rewards\HuntRewardValueGenerator;use App\Domain\Random\RandomNumberGenerator;use App\Models\HuntEnemy;use App\Models\Monster;use Illuminate\Support\Collection;use InvalidArgumentException;use PHPUnit\Framework\TestCase;
class RewardValueFixedRandom implements RandomNumberGenerator{private $values;public function __construct(array $values){$this->values=$values;}public function randomInt(int $minimum,int $maximum):int{$value=array_shift($this->values);if($value<$minimum||$value>$maximum)throw new InvalidArgumentException();return$value;}}
class HuntRewardValuesTest extends TestCase{public function test_generates_in_enemy_position_order_and_sums_values(){$first=new Monster(['experience_reward'=>10,'gold_min'=>3,'gold_max'=>8]);$first->id=1;$second=new Monster(['experience_reward'=>20,'gold_min'=>8,'gold_max'=>16]);$second->id=2;$late=new HuntEnemy(['position'=>2,'monster_id'=>2]);$early=new HuntEnemy(['position'=>1,'monster_id'=>1]);$result=(new HuntRewardValueGenerator(new RewardValueFixedRandom([4,12])))->generate(new Collection([$late,$early]),new Collection([1=>$first,2=>$second]));$this->assertSame(16,$result->gold());$this->assertSame(30,$result->experience());}public function test_fixed_gold_does_not_consume_randomness(){$monster=new Monster(['experience_reward'=>7,'gold_min'=>5,'gold_max'=>5]);$monster->id=1;$enemy=new HuntEnemy(['position'=>1,'monster_id'=>1]);$result=(new HuntRewardValueGenerator(new RewardValueFixedRandom([])))->generate(new Collection([$enemy]),new Collection([1=>$monster]));$this->assertSame(5,$result->gold());$this->assertSame(7,$result->experience());}}
